      { "name": "PostgreSQL Read Replica(s)", "responsibility": "Offload read-heavy queries (order search, delivery history aggregation)", "boundaries": "To be introduced in Phase 1; async replication from primary" },
      { "name": "Search/Cache Layer", "responsibility": "Accelerate order search by customer and frequent aggregation queries", "boundaries": "To be introduced in Phase 2; reduces direct DB load for read-heavy patterns" }
    ],
    "interfaces": [
      { "from": "API Tier", "to": "PostgreSQL Primary", "contract": "All writes + real-time reads via connection pool", "coupling_type": "tight — single database dependency" },
      { "from": "API Tier", "to": "PostgreSQL Read Replica", "contract": "Read queries routed for order search & aggregation (eventual consistency acceptable)", "coupling_type": "loose — can fall back to primary" },
      { "from": "PostgreSQL Primary", "to": "PostgreSQL Read Replica", "contract": "Streaming replication with <1s lag target", "coupling_type": "infrastructure coupling" },
      { "from": "API Tier", "to": "Search/Cache Layer", "contract": "Order search queries, delivery aggregation cache", "coupling_type": "loose — fallback to replica/primary" }
